mapper.update:
UPDATE hall
SET seat_count     = #{seatCount},
    movie_time     = #{movieTime},
    start_time     = #{startTime},
    movie_id       = #{movieId},
    today_show_cnt = #{todayShowCnt}
WHERE hall_id = #{hallId}
  AND seat_id = #{seatId}

UPDATE movie
SET    hall_id = NULL
WHERE  hall_id = #{hallId}

mapper.delete:
DELETE FROM hall
WHERE  hall_id = #{param1}
  AND  seat_id = #{param2}

mapper.select:
SELECT hall_id, seat_id, seat_count, movie_time, start_time, movie_id, today_show_cnt
FROM   hall
WHERE  hall_id = #{param1}
  AND  seat_id = #{param2}

SELECT hall_id, seat_id, seat_count, movie_time, start_time, movie_id, today_show_cnt
FROM   hall
WHERE  movie_id = #{param1}
  AND  hall_id  = #{param2}
ORDER BY start_time, seat_id
